import{_ as e,o as s,c as p,a2 as i}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"系统设计：需求、规模估算与架构取舍","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"system-design-requirements-estimation-architecture-tradeoffs"},"headers":[],"relativePath":"05-backend-data/notes/09-system-design/01-requirements-estimation-architecture-tradeoffs.md","filePath":"05-backend-data/notes/09-system-design/01-requirements-estimation-architecture-tradeoffs.md","lastUpdated":null}'),t={name:"05-backend-data/notes/09-system-design/01-requirements-estimation-architecture-tradeoffs.md"};function n(r,a,l,o,h,d){return s(),p("div",null,[...a[0]||(a[0]=[i(`<h1 id="系统设计-需求、规模估算与架构取舍" tabindex="-1">系统设计：需求、规模估算与架构取舍 <a class="header-anchor" href="#系统设计-需求、规模估算与架构取舍" aria-label="Permalink to &quot;系统设计：需求、规模估算与架构取舍&quot;">​</a></h1><p>系统设计不是列出 Redis、Kafka、Kubernetes 的练习，而是把一个可验证的需求转换为在明确规模、故障和成本约束下可运行、可恢复、可演进的方案。</p><h2 id="设计输出与学习边界" tabindex="-1">设计输出与学习边界 <a class="header-anchor" href="#设计输出与学习边界" aria-label="Permalink to &quot;设计输出与学习边界&quot;">​</a></h2><p>本篇覆盖需求、非功能需求、规模估算、API、数据模型、高层架构、读写流程、扩展性、一致性、高可用、安全、可观测性、成本和 Trade-off。</p><p>文末用 URL Shortener 与文件存储演示完整推理。通知、任务队列、订单、支付、搜索、IM、协作文档、设计工具、聊天与 RAG 平台也应使用相同顺序，但每个系统的事实来源和不变量不同。</p><p>前置知识：HTTP API、关系数据库、缓存、对象存储、消息队列、认证授权与基础指标。</p><h2 id="从问题而不是组件开始" tabindex="-1">从问题而不是组件开始 <a class="header-anchor" href="#从问题而不是组件开始" aria-label="Permalink to &quot;从问题而不是组件开始&quot;">​</a></h2><p>功能需求描述用户可以完成什么，以及结果如何验收。</p><p>非功能需求描述系统在什么条件下仍算可用，包括延迟、可用性、数据丢失、隔离、安全、合规与预算。</p><p>约束描述已经存在的系统、团队能力、地域、交付时间和不能破坏的兼容性。</p><p>未知项必须列为待确认假设，不能被悄悄填成“无限流量”或“绝不失败”。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;需求与不变量&quot;] --&gt; B[&quot;规模与风险假设&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;API 与数据模型&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;读写架构&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;容量、恢复与成本&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;验证与迭代&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; A</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>图中的顺序不是瀑布流程。发现容量、权限或恢复约束后，应回到 API、数据模型或需求重新收敛。</p><h2 id="需求清单" tabindex="-1">需求清单 <a class="header-anchor" href="#需求清单" aria-label="Permalink to &quot;需求清单&quot;">​</a></h2><h3 id="功能需求" tabindex="-1">功能需求 <a class="header-anchor" href="#功能需求" aria-label="Permalink to &quot;功能需求&quot;">​</a></h3><p>写出主用户路径、管理员路径和后台路径。</p><p>每条路径给出输入、成功结果、可见状态和失败结果。</p><p>例如“创建短链接”不是完整需求；还应说明是否允许自定义别名、过期、删除、修改目标和统计。</p><p>例如“上传文件”不是完整需求；还应说明最大大小、可见范围、病毒扫描、预览和删除后的行为。</p><h3 id="不变量" tabindex="-1">不变量 <a class="header-anchor" href="#不变量" aria-label="Permalink to &quot;不变量&quot;">​</a></h3><p>不变量是无论重试、并发、故障切换还是后台重放都必须成立的规则。</p><p>短链接别名在其有效范围内只能映射到一个目标。</p><p>订单只能由被授权主体查看或修改。</p><p>文件下载必须在授权检查后进行，签名地址过期后不能继续作为长期凭证。</p><p>把不变量放在服务端状态转换、数据库约束或受控存储策略中；不要仅依靠前端校验或提示词。</p><h3 id="非功能目标" tabindex="-1">非功能目标 <a class="header-anchor" href="#非功能目标" aria-label="Permalink to &quot;非功能目标&quot;">​</a></h3><p>定义延迟时使用百分位和请求范围，例如“已认证重定向的 99% 在 100ms 内完成”。</p><p>定义可用性时说明分母、排除条件和时间窗。</p><p>定义数据目标时区分 RPO 与 RTO：前者允许丢失多少时间的数据，后者允许多长时间恢复服务。</p><p>定义成本时区分固定资源、按请求、存储、出网、日志保留与人工运维成本。</p><h2 id="规模估算" tabindex="-1">规模估算 <a class="header-anchor" href="#规模估算" aria-label="Permalink to &quot;规模估算&quot;">​</a></h2><p>估算不是猜测精确数字，而是让架构选择有量级依据。</p><p>先记录日活、每用户操作数、读写比、峰值系数、对象大小、保留期和增长率。</p><p>平均 QPS 约等于日请求数除以 86,400。</p><p>峰值 QPS 等于平均 QPS 乘峰值系数；峰值系数应来自活动、时区或历史流量，而非固定写成十倍。</p><p>存储量等于每日新增对象数乘平均对象大小乘保留天数，再加副本、索引、版本和恢复余量。</p><p>网络量同时计算入站与出站。文件下载和 CDN 回源常常比元数据数据库先成为成本与容量瓶颈。</p><p>连接、队列和并发的上限要从下游能力倒推。数据库只能安全承受 200 个并发查询时，入口不能无限接收并把等待转化为内存占用。</p><p>把每个假设写在设计文档中，并在压测、真实指标或业务变化后更新。</p><h2 id="api-设计" tabindex="-1">API 设计 <a class="header-anchor" href="#api-设计" aria-label="Permalink to &quot;API 设计&quot;">​</a></h2><p>API 是调用者与服务端之间的契约，不是数据库表的镜像。</p><p>为创建、读取、更新、删除和异步操作分别定义资源、方法、状态码、认证和错误模型。</p><p>创建具有外部副作用的资源时接受幂等键；服务端把同一主体和同一键绑定到第一次完成的结果。</p><p>分页使用稳定排序和游标时，游标应编码排序位置与过滤条件的必要版本，不能被任意猜测后读取越权数据。</p><p>错误响应至少区分输入无效、未认证、无权、资源不存在、冲突、限流、依赖暂时失败和内部错误。</p><p>不要因安全而总把越权返回 404；选择 403 或 404 是产品泄露模型的一部分，但内部审计必须保留真实原因。</p><h2 id="数据模型与事实来源" tabindex="-1">数据模型与事实来源 <a class="header-anchor" href="#数据模型与事实来源" aria-label="Permalink to &quot;数据模型与事实来源&quot;">​</a></h2><p>数据模型先列实体、关系、生命周期和唯一性。</p><p>为每个字段说明来源、可修改者、审计要求和删除策略。</p><p>事务内的数据是该服务的事实来源；缓存、搜索索引、统计表和通知是派生数据。</p><p>派生数据延迟、重放或丢失时，系统应能从事实来源重建，而不是把搜索索引当主数据库更新。</p><p>高频读取数据可缓存，但权限、库存、支付状态和删除状态需要明确的失效与回源语义。</p><h2 id="高层架构" tabindex="-1">高层架构 <a class="header-anchor" href="#高层架构" aria-label="Permalink to &quot;高层架构&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U[&quot;用户或客户端&quot;] --&gt; G[&quot;鉴权与 API 网关&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; S[&quot;业务服务&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; D[&quot;事实数据库&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; O[&quot;对象存储或缓存&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; Q[&quot;Outbox 与异步队列&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q --&gt; W[&quot;后台工作者&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; T[&quot;日志、指标与 Trace&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>组件图只保留职责和数据流。每个箭头都应回答认证在哪里发生、超时多少、重试是否幂等、失败后保留什么状态。</p><p>网关可处理 TLS 终止、路由与粗粒度限流，但业务授权不能只依赖网关规则。</p><p>数据库维护事实和约束；对象存储保存大对象；消息系统解耦可延后工作；观测系统帮助判断方案是否仍满足目标。</p><h2 id="读写流程" tabindex="-1">读写流程 <a class="header-anchor" href="#读写流程" aria-label="Permalink to &quot;读写流程&quot;">​</a></h2><p>写流程从认证开始，验证输入和对象权限，再执行事务状态转换。</p><p>需要异步处理时，在同一事务写入 outbox；后台转发事件，消费者按稳定业务键去重。</p><p>读流程先确认主体可读取资源，再选择缓存、数据库、对象存储或搜索索引。</p><p>缓存未命中只能回源到事实来源或受控派生过程；不能用一个过期缓存值绕过删除和权限变更。</p><p>为每个流程写明 deadline、取消、错误响应和审计字段。</p><h2 id="扩展性与一致性" tabindex="-1">扩展性与一致性 <a class="header-anchor" href="#扩展性与一致性" aria-label="Permalink to &quot;扩展性与一致性&quot;">​</a></h2><p>扩展性是测得瓶颈后的改变。</p><p>读多时可先增加缓存、CDN 或读取副本；写多时检查索引、批量、队列、分区和事务竞争。</p><p>数据大到单库无法满足容量、隔离或恢复目标时再评估分片；先确定分片键、跨分片查询与迁移路径。</p><p>一致性目标按不变量选择。用户名唯一、扣库存和权限撤销可能需要强协调；点击统计、搜索结果和通知展示通常允许最终收敛。</p><p>Read-after-write 只应作用于刚保存、刚支付等需要会话保证的路径，避免把全部读取压到主库。</p><h2 id="高可用与恢复" tabindex="-1">高可用与恢复 <a class="header-anchor" href="#高可用与恢复" aria-label="Permalink to &quot;高可用与恢复&quot;">​</a></h2><p>高可用不等于多部署几个副本。依赖的数据库、DNS、身份服务、密钥、对象存储、队列和发布系统都可能决定可用性。</p><p>先定义故障域：进程、节点、可用区、区域和供应商。</p><p>为每个故障域定义检测、隔离、切换、数据校验、回滚和通知责任。</p><p>备份必须定期 restore 到隔离环境，验证密钥、版本、权限、容量和业务校验和。</p><h2 id="安全与隐私" tabindex="-1">安全与隐私 <a class="header-anchor" href="#安全与隐私" aria-label="Permalink to &quot;安全与隐私&quot;">​</a></h2><p>身份认证、资源授权、租户隔离、速率限制和输入限制在服务端执行。</p><p>参数化查询防 SQL 注入；对象路径在规范化后验证根目录；服务端取 URL 时防 SSRF；更新接口使用允许字段列表防 Mass Assignment。</p><p>Secret 由密钥管理或部署平台注入，不写入镜像、仓库、日志、错误响应或前端包。</p><p>遥测采用字段白名单和脱敏，避免记录 Cookie、Authorization、密码、签名 URL 与原始个人内容。</p><h2 id="可观测性" tabindex="-1">可观测性 <a class="header-anchor" href="#可观测性" aria-label="Permalink to &quot;可观测性&quot;">​</a></h2><p>每个请求生成或传播 request ID 与 trace context。</p><p>记录结构化日志：服务、版本、路由、状态、延迟、错误类别和脱敏主体标识。</p><p>指标至少包含请求 rate、错误率、延迟直方图、队列积压、资源饱和与业务成功率。</p><p>告警应指向用户影响或容量风险，并附 runbook、仪表盘和升级条件。</p><h2 id="案例一-url-shortener" tabindex="-1">案例一：URL Shortener <a class="header-anchor" href="#案例一-url-shortener" aria-label="Permalink to &quot;案例一：URL Shortener&quot;">​</a></h2><p>需求：创建短链接、重定向、别名、过期、删除和访问统计。</p><p>不变量：有效别名唯一；删除后不可继续重定向；管理员只能管理自身或被授权域名。</p><p>写 API 为 <code>POST /links</code>，接受目标 URL、可选别名、过期时间和幂等键。</p><p>数据库以别名唯一索引保护并发创建；链接表是事实来源。</p><p>重定向读取先查缓存，未命中查数据库并回填短 TTL；过期或删除状态必须在回填前检查。</p><p>点击事件异步写入队列，统计系统失败不影响重定向主路径。</p><p>验证：并发创建同一别名只有一个成功；暂停统计消费者后重定向仍可用；删除后缓存失效且访问得到受控结果。</p><p>失败分支：把访问统计同步写关系库会把分析负载和数据库延迟直接加入用户跳转延迟。</p><p>成本取舍：小规模可单库加缓存；超大读流量再引入 CDN 和多区域读取，前提是删除与权限变化的失效语义仍可验证。</p><h2 id="案例二-用户文件存储" tabindex="-1">案例二：用户文件存储 <a class="header-anchor" href="#案例二-用户文件存储" aria-label="Permalink to &quot;案例二：用户文件存储&quot;">​</a></h2><p>需求：用户上传、列出、下载、删除、扫描和预览文件。</p><p>客户端先请求上传会话；服务检查身份、租户配额、文件用途和允许大小后返回短时、受限操作的上传凭证。</p><p>文件数据直接进入对象存储，应用只持久化对象 key、大小、内容摘要、所有者、扫描状态和生命周期。</p><p>上传完成事件触发扫描与预览工作者；下载仅对 <code>SAFE</code> 状态且通过资源授权的对象签发短时下载凭证。</p><p>验证：伪造 MIME、超大文件、扫描超时、重复完成回调、已删除对象和跨租户 object key 都有明确状态和审计。</p><p>失败分支：让大文件经 API 服务器中转会耗尽连接、内存和带宽；把对象 key 当授权凭证会造成 IDOR。</p><p>成本取舍：对象存储降低持久化运维，但版本、生命周期、出网、预览和病毒扫描仍会产生可观成本。</p><h2 id="设计评审清单" tabindex="-1">设计评审清单 <a class="header-anchor" href="#设计评审清单" aria-label="Permalink to &quot;设计评审清单&quot;">​</a></h2><ol><li><p>是否写明用户目标、管理员目标和明确不做的范围？</p></li><li><p>每个吞吐、存储和延迟数字是否有来源或可验证假设？</p></li><li><p>每条 API 是否定义认证、授权、幂等、错误和限流？</p></li><li><p>事实来源、派生数据、重建路径和删除语义是否清楚？</p></li><li><p>关键读写流程是否包含超时、重试、取消和重复请求？</p></li><li><p>哪些不变量强一致，哪些数据允许最终一致，理由是什么？</p></li><li><p>一个区域、一个依赖或一次发布失败时，如何检测、降级和恢复？</p></li><li><p>是否能从线上版本反查 commit、镜像、配置和基础设施变更？</p></li><li><p>成本是否包含日志、备份、网络、恢复演练和人工维护？</p></li><li><p>更简单方案为何暂时不足，更复杂方案为何暂时不需要？</p></li></ol><h2 id="练习" tabindex="-1">练习 <a class="header-anchor" href="#练习" aria-label="Permalink to &quot;练习&quot;">​</a></h2><p>任选通知、任务队列、订单、支付、搜索、IM、协作文档、设计工具、聊天或 RAG 平台，写一页系统设计。</p><p>验收：评审者能够指出一个事实来源、三个不变量、两个量级假设、一次部分失败处理、一条 SLO 指标和一个被明确拒绝的复杂方案。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://sre.google/workbook/non-abstract-design/" target="_blank" rel="noreferrer">Google SRE：非抽象的大规模设计</a>（访问日期：2026-07-23）</li><li><a href="https://docs.aws.amazon.com/wellarchitected/latest/framework/welcome.html" target="_blank" rel="noreferrer">AWS Well-Architected Framework</a>（访问日期：2026-07-23）</li><li><a href="https://sre.google/sre-book/handling-overload/" target="_blank" rel="noreferrer">Google SRE：处理过载</a>（访问日期：2026-07-23）</li></ul>`,109)])])}const b=e(t,[["render",n]]);export{u as __pageData,b as default};
